///|
pub(all) suberror DecodeError {
  Empty
  Unknown(Byte)
} derive(Debug)

///|
pub fn decode_tag(packet : Bytes) -> String raise {
  match packet {
    [] => raise DecodeError::Empty
    [tag, ..] => match tag {
      b'\x01' => "ping"
      b'\x02' => "pong"
      _ => raise DecodeError::Unknown(tag)
    }
  }
}

